// resolvePowerFloor maps an inferred power class to a concrete ladder floor.
// When the ladder cannot satisfy the requested class, it degrades through the
// hierarchy (Smart → Standard → Cheap) per ADR-024 P1 ("cheapest first") so
// dispatch hands the bead to Fizeau with a viable bound rather than failing
// outright. Returning (0, false) means "no MinPower pin; let Fizeau pick".
func resolvePowerFloor(powerClass policyescalation.PowerClass, ladder escalationFloorFinder) (int, bool) {
	switch powerClass {
	case policyescalation.PowerSmart:
		if floor, err := highestViableEscalationFloor(ladder); err == nil {
			return floor, true
		}
		return resolvePowerFloor(policyescalation.PowerStandard, ladder)
	case policyescalation.PowerStandard:
		first, err := nextEscalationFloor(ladder, 0)
		if err != nil {
			return 0, false
		}
		second, err := nextEscalationFloor(ladder, first)
		if err != nil {
			return first, true
		}
		return second, true
	default:
		return 0, false
	}
}

// zeroConfigInitialMinPower selects the initial MinPower for a bead when the
// caller has no explicit routing flags or project routing config. The third
// return value carries a degradation note when the inferred class could not
// be pinned to a ladder floor and was downgraded to Cheap-equivalent
// (no MinPower pin). Callers should propagate the note into RoutingIntentNote
// so the evidence stream records why dispatch ended up unpinned.
func zeroConfigInitialMinPower(b *bead.Bead, powerClass policyescalation.PowerClass, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, string, bool) {
	if powerClass == "" {
		return baseMinPower, agent.ExecuteBeadReport{}, "", false
	}
	powerFloor, hasPowerFloor := resolvePowerFloor(powerClass, ladder)
	if !hasPowerFloor {
		note := ""
		if powerClass != policyescalation.PowerCheap {
			note = fmt.Sprintf(
				"no ladder floor for inferred powerClass %s; degraded to cheap-equivalent (no MinPower pin)",
				powerClass,
			)
		}
		return baseMinPower, agent.ExecuteBeadReport{}, note, false
	}
	if powerFloor > baseMinPower {
		if maxPower > 0 && powerFloor >= maxPower {
			return baseMinPower, routeUnavailableReport(b, powerFloor, maxPower, nil), "", true
		}
		return powerFloor, agent.ExecuteBeadReport{}, "", false
	}
	return baseMinPower, agent.ExecuteBeadReport{}, "", false
}

func routeUnavailableReport(b *bead.Bead, minPower, maxPower int, cause error) agent.ExecuteBeadReport {
	beadID := ""
	if b != nil {
		beadID = b.ID
	}
	detail := fmt.Sprintf("route unavailable: no viable routing candidate satisfies requested MinPower %d", minPower)
	if maxPower > 0 {
		detail += fmt.Sprintf(" and MaxPower %d", maxPower)
	}
	if cause != nil {
		detail += ": " + cause.Error()
	}
	return agent.ExecuteBeadReport{
		BeadID:        beadID,
		Status:        agent.ExecuteBeadStatusExecutionFailed,
		Detail:        detail,
		OutcomeReason: agent.FailureModeNoViableProvider,
	}
}

func runEscalatingPowerAttempts(
	ctx context.Context,
	initialMinPower int,
	ladder escalationFloorFinder,
	attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
	recordAttempt func(agent.ExecuteBeadReport),
	perBeadTracker *policyescalation.PerBeadCostTracker,
	allowInfrastructureRetry bool,
) (agent.ExecuteBeadReport, error) {
	minPower := initialMinPower
	floors := tryLoopFloorFinder{ladder: ladder}
	for {
		report, err := attempt(ctx, minPower)
		if recordAttempt != nil && report.BeadID != "" {
			recordAttempt(report)
		}
		if perBeadTracker != nil {
			perBeadTracker.Add(report.Harness, report.CostUSD)
		}
		if err != nil {
			return report, err
		}
		if perBeadTracker != nil {
			if detail, tripped := perBeadTracker.Tripped(); tripped {
				report.Status = agent.ExecuteBeadStatusExecutionFailed
				report.Detail = detail
				report.CostUSD = perBeadTracker.Spent()
				return report, nil
			}
		}
		normalizeProviderConnectivityRetryReport(&report)
		transition := executeloop.DecideAttemptTransition(executeloop.AttemptTransitionInput{
			Status:                   report.Status,
			Detail:                   report.Detail,
			CurrentMinPower:          minPower,
			ActualPower:              report.ActualPower,
			OutcomeReason:            report.OutcomeReason,
			Disrupted:                report.Disrupted,
			BudgetExhausted:          isBudgetExhaustedFailure(report),
			AllowInfrastructureRetry: allowInfrastructureRetry,
		}, floors)
		if transition.Action != executeloop.TryLoopActionRetryPower {
			return report, nil
		}
		minPower = transition.NextMinPower
	}
}

package executeloop

import (
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// TryLoopState names the in-memory states used while ddx try/work evaluates a
// single bead attempt. Persisted bead lifecycle remains the six statuses owned
// by TD-027; these states are control-flow states only.
type TryLoopState string

const (
	TryLoopStateClassifyResult TryLoopState = "classify_result"
	TryLoopStateRetryPower     TryLoopState = "retry_power"
	TryLoopStateStopAttempt    TryLoopState = "stop_attempt"
)

// TryLoopAction is the action selected by the attempt state machine.
type TryLoopAction string

const (
	TryLoopActionStop       TryLoopAction = "stop"
	TryLoopActionRetryPower TryLoopAction = "retry_power"
)

// FloorFinder returns the next viable MinPower floor above the supplied power.
type FloorFinder interface {
	Next(actualPower int) (int, error)
}

// AttemptTransitionInput is the complete input the try-loop state machine needs
// to decide whether another implementation attempt is useful.
type AttemptTransitionInput struct {
	Status          string
	Detail          string
	CurrentMinPower int
	ActualPower     int
	// OutcomeReason carries the worker's typed failure classification. When
	// populated, only semantic acceptance/review reasons are allowed to
	// advance the power ladder; structural and infrastructure reasons stop
	// without escalating MinPower.
	OutcomeReason string

	Disrupted                bool
	BudgetExhausted          bool
	AllowInfrastructureRetry bool
}

// AttemptTransition is the state-machine decision for one completed attempt.
type AttemptTransition struct {
	State        TryLoopState
	Action       TryLoopAction
	NextMinPower int
	Reason       string
}

// DecideAttemptTransition implements the ddx try retry state machine for one
// attempt result. The default bias is forward progress: semantic failures move
// up the model-power ladder, while retryable provider-connectivity failures can
// be retried immediately with MinPower set just above the failed route's actual
// power. Infrastructure failures without concrete route evidence still stop the
// current attempt; a smarter model cannot fix an absent service with no
// alternate power signal.
func DecideAttemptTransition(input AttemptTransitionInput, ladder FloorFinder) AttemptTransition {
	if input.Disrupted && strings.TrimSpace(input.OutcomeReason) != "provider_connectivity" && !isProviderConnectivityDetail(input.Detail) {
		return stopTransition("disrupted")
	}
	if input.BudgetExhausted {
		return stopTransition("budget_exhausted")
	}
	if strings.TrimSpace(input.Status) == "land_conflict" {
		return stopTransition("land_conflict")
	}
	if reason := strings.TrimSpace(input.OutcomeReason); reason != "" && !isSemanticRetryOutcomeReason(reason) && reason != "provider_connectivity" {
		return stopTransition("non_semantic_outcome_reason")
	}
	if !escalation.ShouldEscalate(input.Status) {
		return stopTransition("terminal_status")
	}

	if escalation.IsInfrastructureFailure(input.Status, input.Detail) {
		if !input.AllowInfrastructureRetry || input.ActualPower <= 0 || !isProviderConnectivityDetail(input.Detail) {
			return stopTransition("infrastructure_no_retry_route")
		}
		next := input.ActualPower + 1
		if next <= input.CurrentMinPower {
			next = input.CurrentMinPower + 1
		}
		return AttemptTransition{
			State:        TryLoopStateRetryPower,
			Action:       TryLoopActionRetryPower,
			NextMinPower: next,
			Reason:       "infrastructure_retry_with_higher_min_power",
		}
	}

	basis := input.CurrentMinPower
	if input.ActualPower > 0 {
		basis = input.ActualPower
	}
	next, err := nextLadderFloor(ladder, basis)
	if err != nil {
		return stopTransition("power_ladder_exhausted")
	}
	return AttemptTransition{
		State:        TryLoopStateRetryPower,
		Action:       TryLoopActionRetryPower,
		NextMinPower: next,
		Reason:       "semantic_retry_with_higher_min_power",
	}
}

func isSemanticRetryOutcomeReason(reason string) bool {
	switch strings.TrimSpace(reason) {
	case "tests_red",
		"test_failure",
		"build_failure",
		"review_block",
		"review_request_changes",
		"post_run_check_failed":
		return true
	default:
		return false
	}
}

func stopTransition(reason string) AttemptTransition {
	return AttemptTransition{
		State:  TryLoopStateStopAttempt,
		Action: TryLoopActionStop,
		Reason: reason,
	}
}

func nextLadderFloor(ladder FloorFinder, basis int) (int, error) {
	if ladder == nil {
		return 0, errNoFloorFinder{}
	}
	return ladder.Next(basis)
}

type errNoFloorFinder struct{}

func (errNoFloorFinder) Error() string { return "no floor finder configured" }

func isProviderConnectivityDetail(detail string) bool {
	lower := strings.ToLower(detail)
	for _, marker := range []string{"provider_connectivity", "connection refused", "no route to host", "network is unreachable", "i/o timeout", "connection reset", "dial tcp"} {
		if strings.Contains(lower, marker) {
			return true
		}
	}
	return false
}

// Package executeloop defines the canonical spec type for work workers.
// It is import-safe: no dependency on cobra, server, or transport packages.
package executeloop

import (
	"encoding/json"
	"fmt"
	"strconv"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// SpecCurrentVersion is the single spec version supported by this client and
// server. Forward-compat stance: a client MUST set SpecVersion = SpecCurrentVersion;
// a server receiving an unknown version SHOULD reject with an error rather than
// silently misinterpreting fields. There is no backwards-compat shim — upgrade
// client and server together.
const SpecCurrentVersion = 1

// Mode controls how the work terminates.
type Mode string

const (
	// ModeOnce runs one bead (or none if the queue is empty) then exits.
	ModeOnce Mode = "once"
	// ModeDrain processes all ready beads then exits.
	ModeDrain Mode = "drain"
	// ModeWatch processes all ready beads, then sleeps for IdleInterval and
	// rechecks, looping indefinitely until interrupted.
	ModeWatch Mode = "watch"
)

// Duration wraps time.Duration with JSON support that marshals as a string
// (e.g., "30s") and unmarshals both strings ("30s") and numeric nanoseconds.
type Duration struct {
	time.Duration
}

func (d Duration) MarshalJSON() ([]byte, error) {
	return json.Marshal(d.String())
}

func (d *Duration) UnmarshalJSON(b []byte) error {
	// Try string first.
	var s string
	if err := json.Unmarshal(b, &s); err == nil {
		parsed, err := time.ParseDuration(s)
		if err != nil {
			return fmt.Errorf("executeloop: invalid duration string %q: %w", s, err)
		}
		d.Duration = parsed
		return nil
	}
	// Try numeric nanoseconds.
	var ns int64
	if err := json.Unmarshal(b, &ns); err == nil {
		d.Duration = time.Duration(ns)
		return nil
	}
	return fmt.Errorf("executeloop: cannot unmarshal %s as duration (want string or nanosecond integer)", strconv.Quote(string(b)))
}

// ExecuteLoopSpec is the canonical, transport-agnostic specification for an
// work worker. All transports (cobra, REST, GraphQL) map into this type
// before persisting or dispatching.
type ExecuteLoopSpec struct {
	ProjectRoot string `json:"project_root,omitempty"`
	Harness     string `json:"harness,omitempty"`
	Model       string `json:"model,omitempty"`
	Profile     string `json:"profile,omitempty"`
	Provider    string `json:"provider,omitempty"`
	Effort      string `json:"effort,omitempty"`
	LabelFilter string `json:"label_filter,omitempty"`
	// AttemptBackend selects the execute-bead workspace/transport backend for
	// each attempt. Empty uses executions.attempt_backend or the binary default.
	AttemptBackend string `json:"attempt_backend,omitempty"`

	// Mode controls loop termination. Defaults to ModeDrain via ApplyDefaults.
	Mode Mode `json:"mode,omitempty"`

	// IdleInterval is the sleep duration between queue polls when Mode=watch
	// and no execution-ready work is found.
	IdleInterval Duration `json:"idle_interval,omitempty"`

	NoReview               bool   `json:"no_review,omitempty"`
	ReviewHarness          string `json:"review_harness,omitempty"`
	ReviewModel            string `json:"review_model,omitempty"`
	IgnoreCooldown         bool   `json:"ignore_cooldown,omitempty"`
	CooldownOverrideReason string `json:"cooldown_override_reason,omitempty"`

	// OpaquePassthrough skips DDx-side route validation and config
	// harness/model injection (CONTRACT-003 / FEAT-010).
	OpaquePassthrough bool `json:"opaque_passthrough,omitempty"`

	MaxCostUSD         float64  `json:"max_cost_usd,omitempty"`
	MaxBeadCostUSD     float64  `json:"max_bead_cost_usd,omitempty"`
	MaxRecoveryCostUSD float64  `json:"max_recovery_cost_usd,omitempty"`
	PreClaimTimeout    Duration `json:"preclaim_timeout,omitempty"`
	RequestTimeout     Duration `json:"request_timeout,omitempty"`
	RateLimitMaxWait   Duration `json:"rate_limit_max_wait,omitempty"`
	// RouteResolutionTimeout bounds routing preflight and the resolveRoute
	// viability check so a hung resolver cannot wedge the worker. Zero uses the
	// binary default (agent.DefaultRouteResolutionTimeout, 60s).
	RouteResolutionTimeout Duration `json:"route_resolution_timeout,omitempty"`
	MinPower               int      `json:"min_power,omitempty"`
	MaxPower               int      `json:"max_power,omitempty"`

	// FromRev, if set, narrows execution to beads introduced after this git revision.
	FromRev string `json:"from_rev,omitempty"`

	// SpecVersion must equal SpecCurrentVersion. See SpecCurrentVersion for the
	// client/server forward-compat stance.
	SpecVersion int `json:"spec_version,omitempty"`
}

// DispatchOptions carries control-plane fields used at dispatch time. It is not
// persisted into the worker record.
type DispatchOptions struct {
	// Local, when true, runs the worker in-process rather than via the server API.
	Local bool `json:"local,omitempty"`
	// JSON is the raw JSON payload to forward when dispatching via REST/GraphQL.
	// Callers that build the request body manually may set this instead of
	// populating an ExecuteLoopSpec.
	JSON string `json:"json,omitempty"`
}

// ApplyDefaults fills in zero-value fields with their canonical defaults.
// Safe to call on a zero-value spec.
func (s *ExecuteLoopSpec) ApplyDefaults() {
	if s.Mode == "" {
		s.Mode = ModeDrain
	}
	if s.Mode == ModeWatch && s.IdleInterval.Duration == 0 {
		s.IdleInterval = Duration{30 * time.Second}
	}
	if s.SpecVersion == 0 {
		s.SpecVersion = SpecCurrentVersion
	}
	if s.MaxRecoveryCostUSD == 0 {
		s.MaxRecoveryCostUSD = escalation.DefaultMaxRecoveryCostUSD
	}
}

// Validate checks that the spec is well-formed after ApplyDefaults has run.
func (s *ExecuteLoopSpec) Validate() error {
	switch s.Mode {
	case ModeOnce, ModeDrain, ModeWatch:
	default:
		return fmt.Errorf("executeloop: unknown mode %q (want once, drain, or watch)", s.Mode)
	}
	if s.Mode != ModeWatch && s.IdleInterval.Duration != 0 {
		return fmt.Errorf("executeloop: idle_interval is only valid when mode=watch")
	}
	if s.SpecVersion != 0 && s.SpecVersion != SpecCurrentVersion {
		return fmt.Errorf("executeloop: unsupported spec_version %d (want %d)", s.SpecVersion, SpecCurrentVersion)
	}
	return nil
}

package executeloop

import (
	"errors"
	"testing"

	"github.com/stretchr/testify/assert"
)

type testFloorFinder []int

func (f testFloorFinder) Next(actualPower int) (int, error) {
	for _, floor := range f {
		if floor > actualPower {
			return floor, nil
		}
	}
	return 0, errors.New("exhausted")
}

func TestTryLoopStateMachineProviderConnectivityRetriesWithExactHigherFloor(t *testing.T) {
	transition := DecideAttemptTransition(AttemptTransitionInput{
		Status:                   "execution_failed",
		Detail:                   "provider request failed: dial tcp 100.70.199.113:1235: connect: connection refused",
		CurrentMinPower:          0,
		ActualPower:              5,
		AllowInfrastructureRetry: true,
	}, testFloorFinder{5, 7, 9})

	assert.Equal(t, TryLoopStateRetryPower, transition.State)
	assert.Equal(t, TryLoopActionRetryPower, transition.Action)
	assert.Equal(t, 6, transition.NextMinPower)
	assert.Equal(t, "infrastructure_retry_with_higher_min_power", transition.Reason)
}

func TestTryLoopStateMachinePinnedProviderConnectivityStops(t *testing.T) {
	transition := DecideAttemptTransition(AttemptTransitionInput{
		Status:                   "execution_failed",
		Detail:                   "provider request failed: dial tcp 100.70.199.113:1235: connect: connection refused",
		CurrentMinPower:          0,
		ActualPower:              5,
		AllowInfrastructureRetry: false,
	}, testFloorFinder{5, 7, 9})

	assert.Equal(t, TryLoopActionStop, transition.Action)
	assert.Equal(t, "infrastructure_no_retry_route", transition.Reason)
}

func TestTryLoopStateMachineSemanticFailureUsesLadder(t *testing.T) {
	transition := DecideAttemptTransition(AttemptTransitionInput{
		Status:                   "execution_failed",
		Detail:                   "build failed",
		CurrentMinPower:          0,
		ActualPower:              5,
		AllowInfrastructureRetry: true,
	}, testFloorFinder{5, 7, 9})

	assert.Equal(t, TryLoopActionRetryPower, transition.Action)
	assert.Equal(t, 7, transition.NextMinPower)
	assert.Equal(t, "semantic_retry_with_higher_min_power", transition.Reason)
}

func TestTryLoopStateMachineNoRouteEvidenceStopsInfrastructure(t *testing.T) {
	transition := DecideAttemptTransition(AttemptTransitionInput{
		Status:                   "execution_failed",
		Detail:                   "ResolveRoute: no viable routing candidate",
		CurrentMinPower:          0,
		AllowInfrastructureRetry: true,
	}, testFloorFinder{5, 7, 9})

	assert.Equal(t, TryLoopActionStop, transition.Action)
	assert.Equal(t, "infrastructure_no_retry_route", transition.Reason)
}

func TestTryLoopStateMachineQuotaInfrastructureStops(t *testing.T) {
	transition := DecideAttemptTransition(AttemptTransitionInput{
		Status:                   "execution_failed",
		Detail:                   "429 rate limit exceeded",
		CurrentMinPower:          0,
		ActualPower:              5,
		AllowInfrastructureRetry: true,
	}, testFloorFinder{5, 7, 9})

	assert.Equal(t, TryLoopActionStop, transition.Action)
	assert.Equal(t, "infrastructure_no_retry_route", transition.Reason)
}

package agent

import "strings"

// OperatorCancelReason marks a landing preserved because the operator
// cancelled the attempt mid-flight via /api/beads/<id>/cancel. ADR-022
// §Cancel SLA: the worker aborts at the next safe point (between LLM turns /
// git ops) and emits a preserved_for_review result with this exact reason.
const OperatorCancelReason = "operator_cancel"

// PushFailedReasonPrefix is the canonical Reason prefix written by the
// landing layer when `git push` rejects the new tip after a local merge or
// fast-forward succeeded. ClassifyExecuteBeadStatus matches on this prefix
// to map a merged-locally-but-not-pushed outcome to push_failed instead of
// success, so the bead stays open.
const PushFailedReasonPrefix = "landed locally; push failed:"

// PushConflictReasonPrefix marks a more specific failure mode than
// PushFailedReasonPrefix: the local push was rejected because the remote
// advanced, the loop attempted an automatic pull/merge to recover, and the
// merge produced a conflict the loop cannot resolve. The bead is parked for
// human review with a short cooldown rather than a year-long park.
const PushConflictReasonPrefix = "landed locally; push conflict:"

// FailureMode constants classify *why* an execution did not land cleanly.
// They are orthogonal to Outcome/Status: a single failed attempt carries one
// outcome (e.g. preserved) and one failure mode (e.g. merge_conflict) so
// measurement surfaces can aggregate failures by cause.
const (
	FailureModeContextOverflow                = "context_overflow"
	FailureModeMergeConflict                  = "merge_conflict"
	FailureModeTestFailure                    = "test_failure"
	FailureModeBuildFailure                   = "build_failure"
	FailureModeTimeout                        = "timeout"
	FailureModeAuthError                      = "auth_error"
	FailureModeNoChanges                      = "no_changes"
	FailureModeNoEvidenceProduced             = "no_evidence_produced"
	FailureModeRatchetMiss                    = "ratchet_miss"
	FailureModeNoViableProvider               = "no_viable_provider"
	FailureModeProviderConnectivity           = "provider_connectivity"
	FailureModeServerUnavailable              = "server_unavailable"
	FailureModeHarnessNotInstalled            = "harness_not_installed"
	FailureModeBlockedByPassthroughConstraint = "blocked_by_passthrough_constraint"
	FailureModeAgentPowerUnsatisfied          = "agent_power_unsatisfied"
	FailureModeLockContention                 = "lock_contention"
	FailureModeWorktreeLost                   = "worktree_lost"
	// FailureModeRouteResolutionTimeout classifies an attempt that was parked
	// because route resolution / routing preflight exceeded the configured
	// route-resolution timeout. The lease is released and the bead is flagged
	// for operator attention rather than auto-retried (ddx-d8970a7b).
	FailureModeRouteResolutionTimeout = "route_resolution_timeout"
	// FailureModeProgressWatchdog classifies an attempt the progress watchdog
	// terminated because phase-empty heartbeats (harness/model/route all empty)
	// persisted past the phase budget. The worker appeared fresh to the
	// liveness TTL while making no forward progress, so the lease is released
	// and the bead is flagged for operator attention (ddx-dc23f001, parent
	// ddx-8f2e0ebf criterion B).
	FailureModeProgressWatchdog = "progress_watchdog"
	// FailureModeConsecutiveWedge classifies a bead the consecutive-wedge guard
	// stopped re-claiming because it wedged (route_resolution_timeout or
	// progress_watchdog) on consecutive claims up to the threshold. The bead is
	// parked to proposed for operator attention so the single-threaded worker
	// keeps draining the rest of the queue instead of re-wedging the same bead
	// indefinitely (ddx-9714eaac, parent ddx-8f2e0ebf criterion E).
	FailureModeConsecutiveWedge = "consecutive_wedge"
	// FailureModeAttemptIntegrity classifies an attempt that produced commits
	// and a clean agent exit but failed DDx's structured post-agent integrity
	// validation (post-commit mutation, empty pre-commit gate evidence, or
	// uncommitted tracked changes after the implementation commit). It is
	// distinct from implementation/agent failures so operators can tell a DDx
	// validation rejection apart from a genuine task failure (ddx-725b65b4).
	FailureModeAttemptIntegrity = "attempt_integrity"
	// FailureModeLandRetry classifies land/ref/index coordination failures
	// where the implementation result is still valid and the worker should
	// retry/reconcile the landing step instead of escalating implementation.
	FailureModeLandRetry = "land_retry"
	// FailureModeLandOperatorAttention classifies land/ref/index coordination
	// failures where local staged state includes operator-owned work and must
	// be reviewed before DDx lands or retries the result.
	FailureModeLandOperatorAttention = "land_operator_attention"
	FailureModeUnknown               = "unknown"
)

// ResourceExhaustedStopMessage is the operator-visible message emitted when
// execution must stop because the host cannot safely continue draining the
// queue.
const ResourceExhaustedStopMessage = "resource exhausted after cleanup; stopping work loop"

// ClassifyFailureMode derives a failure_mode for a worker-level result from
// its outcome, exit code, and error message. Returns "" when the outcome is
// task_succeeded (success carries no failure mode). task_no_changes always
// maps to FailureModeNoChanges regardless of error text.
//
// For task_failed (or non-zero exit code), the error message is scanned for
// well-known substrings. The order matters: context/auth/timeout patterns
// are checked before generic test/build patterns so a "test timed out"
// classifies as timeout rather than test_failure. Anything unrecognised
// maps to FailureModeUnknown so aggregates never hide a missed pattern.
func ClassifyFailureMode(outcome string, exitCode int, errMsg string) string {
	switch outcome {
	case ExecuteBeadOutcomeTaskSucceeded:
		if exitCode == 0 {
			return ""
		}
		// Degenerate: success outcome with non-zero exit. Treat as unknown
		// failure rather than success so the aggregate flags the anomaly.
	case ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	}

	lower := strings.ToLower(errMsg)
	switch {
	case IsLockContentionError(errMsg):
		return FailureModeLockContention
	case IsWorktreeLostError(errMsg):
		return FailureModeWorktreeLost
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"max_power is less than min_power",
		"max_power exceeds min_power",
		"must be less than max_power",
		"no viable routing candidate for pins",
		"harness cannot satisfy power constraint",
		"harness pin incompatible with power bounds",
		"model pin incompatible with power bounds",
		"provider pin incompatible with power bounds"):
		return FailureModeBlockedByPassthroughConstraint
	case containsAny(lower,
		"agent power unsatisfied",
		"no model meets min_power",
		"no model with power >=",
		"minimum power not achievable",
		"min_power constraint cannot be satisfied"):
		return FailureModeAgentPowerUnsatisfied
	case containsAny(lower,
		"executable file not found in $path",
		"executable file not found",
		"no such file or directory") &&
		containsAny(lower, "exec:", "harness", "claude", "agent", "codex", "gemini"):
		return FailureModeHarnessNotInstalled
	case containsAny(lower,
		"no viable harness",
		"no harness configured",
		"failed to initialize routing service",
		"resolveroute:",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint",
		"no viable provider"):
		return FailureModeNoViableProvider
	case isServerTransportFailureText(lower):
		return FailureModeServerUnavailable
	case containsAny(lower,
		"context length",
		"context_length_exceeded",
		"context window",
		"maximum context",
		"prompt is too long",
		"prompt too long",
		"token limit",
		"too many tokens",
		"exceeds the context"):
		return FailureModeContextOverflow
	case containsAny(lower,
		"unauthorized",
		"401 unauthorized",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"rate limit",
		"rate_limit",
		"429"):
		return FailureModeAuthError
	case containsAny(lower,
		"timeout",
		"timed out",
		"context deadline exceeded",
		"deadline exceeded",
		"signal: killed"):
		return FailureModeTimeout
	case containsAny(lower,
		"merge conflict",
		"ff-merge not possible",
		"merge failed",
		"automatic merge failed"):
		return FailureModeMergeConflict
	case containsAny(lower,
		"build failed",
		"compilation failed",
		"compile error",
		"compilation error",
		"cannot find package",
		"undefined:",
		"undefined reference",
		"syntax error"):
		return FailureModeBuildFailure
	case containsAny(lower,
		"test failed",
		"tests failed",
		"--- fail:",
		"assertion failed",
		"test failure"):
		return FailureModeTestFailure
	}
	if outcome == ExecuteBeadOutcomeTaskFailed && errMsg != "" {
		return FailureModeUnknown
	}
	if exitCode != 0 {
		return FailureModeUnknown
	}
	return ""
}

// IsWorktreeLostError reports whether errMsg describes the execute-bead
// infrastructure losing the isolated attempt worktree before DDx could inspect
// its HEAD. This deliberately requires both a HEAD/worktree signal and a
// missing-path signal so generic harness "no such file" errors do not get
// bucketed as infrastructure loss.
func IsWorktreeLostError(errMsg string) bool {
	lower := strings.ToLower(errMsg)
	hasHeadSignal := containsAny(lower,
		"failed to read worktree head",
		"git rev-parse head",
		"worktree path missing")
	hasMissingPathSignal := containsAny(lower,
		"chdir",
		"no such file or directory",
		"cannot access",
		"does not exist")
	return hasHeadSignal && hasMissingPathSignal
}

package escalation

import (
	"encoding/json"
	"fmt"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// SuccessStatus mirrors agent.ExecuteBeadStatusSuccess. The agent package's
// TestEscalatableStatusesMatchAgentVocab guard catches drift if either side
// renames. Defined locally so escalation does not import agent.
const SuccessStatus = "success"

// EscalatableStatuses is the set of executor status strings that warrant
// retrying with a higher powerClass. Mirrors a subset of agent.ExecuteBeadStatus*
// strings; the agent package has a TestEscalatableStatusesMatchAgentVocab
// guard (see agent/tier_escalation_alignment_test.go) to catch drift.
var EscalatableStatuses = map[string]bool{
	"execution_failed":       true,
	"post_run_check_failed":  true,
	"land_conflict":          true,
	"review_request_changes": true,
	"review_block":           true,
}

// ShouldEscalate reports whether status warrants escalating to the next powerClass.
// Structural failures (e.g. validation errors) do not escalate because a
// smarter model cannot fix a malformed prompt or corrupted bead state.
func ShouldEscalate(status string) bool {
	return EscalatableStatuses[status]
}

// ProviderCooldownDuration is how long an unhealthy harness is skipped before
// re-probing. Five minutes gives most transient errors time to resolve without
// locking out a provider for too long.
//
// Per-harness cooldown tracking moved to the upstream agent service in v0.8.0:
// callers record failures via svc.RecordRouteAttempt and read cooldown state
// via svc.RouteStatus's RouteCandidateStatus.Healthy (ddx-7bc0c8d5).
const ProviderCooldownDuration = 5 * time.Minute

// FormatPowerAttemptBody formats the body of a power-attempt bead event.
func FormatPowerAttemptBody(powerClass, harness, model, probeResult, detail string) string {
	body := fmt.Sprintf("powerClass=%s harness=%s model=%s", powerClass, harness, model)
	if probeResult != "" {
		body += " probe=" + probeResult
	}
	if detail != "" {
		body += "\n" + detail
	}
	return body
}

// EscalationWinningExhausted is the sentinel value written into the
// winning_power_class field of an escalation-summary body when the escalation loop
// ran through every eligible powerClass without producing a successful attempt.
const EscalationWinningExhausted = "exhausted"

// PowerAttemptRecord is one row of an escalation trace. It captures the
// powerClass/harness/model that was tried, the status that attempt returned, and
// the cost/duration the harness reported for that attempt. Skipped powerClasses
// (no viable provider) are recorded with zero cost and zero duration.
type PowerAttemptRecord struct {
	PowerClass string  `json:"power_class"`
	Harness    string  `json:"harness,omitempty"`
	Model      string  `json:"model,omitempty"`
	Status     string  `json:"status"`
	CostUSD    float64 `json:"cost_usd"`
	DurationMS int64   `json:"duration_ms"`
}

// EscalationSummary is the structured body of a kind:escalation-summary bead
// event. It captures the entire escalation trace so an operator can diagnose
// which powerClasses were tried, which one won (if any), and how much the path cost.
type EscalationSummary struct {
	PowerAttempts     []PowerAttemptRecord `json:"power_attempts"`
	WinningPowerClass string               `json:"winning_power_class"`
	TotalCostUSD      float64              `json:"total_cost_usd"`
	WastedCostUSD     float64              `json:"wasted_cost_usd"`
}

// BuildEscalationSummary computes the summary body from the ordered list of
// attempts. winningPowerClass is the string of the powerClass whose attempt succeeded;
// pass "" when the escalation was exhausted, in which case winning_power_class is
// set to EscalationWinningExhausted. Total cost is the sum of all attempt
// costs; wasted cost is the sum of attempts whose status is not
// SuccessStatus.
func BuildEscalationSummary(attempts []PowerAttemptRecord, winningPowerClass string) EscalationSummary {
	out := EscalationSummary{
		PowerAttempts:     append([]PowerAttemptRecord{}, attempts...),
		WinningPowerClass: winningPowerClass,
	}
	if out.WinningPowerClass == "" {
		out.WinningPowerClass = EscalationWinningExhausted
	}
	for _, a := range attempts {
		out.TotalCostUSD += a.CostUSD
		if a.Status != SuccessStatus {
			out.WastedCostUSD += a.CostUSD
		}
	}
	return out
}

// BeadEventAppender records append-only evidence events on a bead. Mirrors
// agent.BeadEventAppender so escalation can append events without importing
// agent. *bead.Store satisfies both interfaces.
type BeadEventAppender interface {
	AppendEvent(id string, event bead.BeadEvent) error
}

// AppendEscalationSummaryEvent writes a kind:escalation-summary event to the
// bead with a JSON body describing the powerClass escalation trace. It is a
// best-effort operation — errors from the underlying store are returned so
// callers can log them, but callers typically ignore the error so telemetry
// failures never abort the main execute-bead flow.
func AppendEscalationSummaryEvent(appender BeadEventAppender, beadID, actor string, attempts []PowerAttemptRecord, winningPowerClass string, createdAt time.Time) error {
	if appender == nil || beadID == "" {
		return nil
	}
	summary := BuildEscalationSummary(attempts, winningPowerClass)
	body, err := json.Marshal(summary)
	if err != nil {
		return err
	}
	return appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "escalation-summary",
		Summary:   fmt.Sprintf("winning_power_class=%s attempts=%d total_cost_usd=%.4f wasted_cost_usd=%.4f", summary.WinningPowerClass, len(attempts), summary.TotalCostUSD, summary.WastedCostUSD),
		Body:      string(body),
		Actor:     actor,
		Source:    "legacy agent work",
		CreatedAt: createdAt,
	})
}

	intakeLog = io.Discard
}
